import { IEmployeeRepository } from './employee.repository';
import { Employee, EmployeeFilters } from './employee.model';

export interface IEmployeeService {
  getEmployee(id: string): Promise<Employee | null>;
  getEmployeeByNumber(employeeNumber: string): Promise<Employee | null>;
  getSubordinates(managerId: string): Promise<Employee[]>;
  isActive(employeeId: string): Promise<boolean>;
  listEmployees(filters?: EmployeeFilters): Promise<Employee[]>;
}

export class EmployeeService implements IEmployeeService {
  constructor(private readonly employeeRepository: IEmployeeRepository) {}

  async getEmployee(id: string): Promise<Employee | null> {
    return this.employeeRepository.findById(id);
  }

  async getEmployeeByNumber(employeeNumber: string): Promise<Employee | null> {
    return this.employeeRepository.findByEmployeeNumber(employeeNumber);
  }

  async getSubordinates(managerId: string): Promise<Employee[]> {
    return this.employeeRepository.findByManagerId(managerId);
  }

  async isActive(employeeId: string): Promise<boolean> {
    const employee = await this.employeeRepository.findById(employeeId);
    return employee?.employment_status === 'ACTIVE';
  }

  async listEmployees(filters?: EmployeeFilters): Promise<Employee[]> {
    return this.employeeRepository.findAll(filters);
  }
}","File: src/modules/employee/employee.controller.ts
import { FastifyRequest, FastifyReply } from 'fastify';
import { z } from 'zod';
import { IEmployeeService } from './employee.service';
import { EmployeeFilters } from './employee.model';

const employeeIdParamSchema = z.object({
  id: z.string().uuid(),
});

const listEmployeesQuerySchema = z.object({
  department: z.string().optional(),
  employmentStatus: z.enum(['ACTIVE', 'INACTIVE', 'TERMINATED']).optional(),
  search: z.string().optional(),
});

export class EmployeeController {
  constructor(private readonly employeeService: IEmployeeService) {}

  async getEmployee(request: FastifyRequest, reply: FastifyReply): Promise<void> {
    const { id } = employeeIdParamSchema.parse(request.params);
    const employee = await this.employeeService.getEmployee(id);
    if (!employee) {
      return reply.status(404).send({ message: 'Employee not found' });
    }
    return reply.send(employee);
  }

  async getEmployees(request: FastifyRequest, reply: FastifyReply): Promise<void> {
    const filters: EmployeeFilters = listEmployeesQuerySchema.parse(request.query);
    const employees = await this.employeeService.listEmployees(filters);
    return reply.send(employees);
  }

  async getSubordinates(request: FastifyRequest, reply: FastifyReply): Promise<void> {
    const { id } = employeeIdParamSchema.parse(request.params);
    const subordinates = await this.employeeService.getSubordinates(id);
    return reply.send(subordinates);
  }
}","File: src/modules/employee/employee.routes.ts
